"use client";

import { useRouter } from "next/navigation";
import { Button, Col, Container, Row } from "react-bootstrap";

export default function Home() {

  const router = useRouter();

  const navigateHandler = () => {
    router.push("/payment");
  }

  return (
    <Container>
      <Row>
        <Col>
          <h1 className="text-danger fw-bold">Dashboard</h1>
          <Button onClick={navigateHandler} variant="primary" className="mt-5 ">
            Next Step
          </Button>
        </Col>
      </Row>
    </Container>
  );
}
